var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 아직 멀었나?!","JPN":"おい、まだなのか！？","ENG":"Hey, are you done yet?","TWN":"喂，還沒結束嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 녀석들, 계속 늘어나고 있는데?","JPN":"こいつら、増え続けてるぞ？","ENG":"These things are growing in number by the minute.","TWN":"這些傢伙不斷在增加耶？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래! 근육 덩어리! 뭐하고 있어? 빨리 해치워 버리지 않고?!","JPN":"そうよ！　筋肉マン！　何してんのよ、さっさと片づけちゃってよ！？","ENG":"Yes, Musclebrain! Just get it over with already!","TWN":"就是啊！肌肉團！你在幹什麼？還不快把他們解決掉？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭔가 이상해......","JPN":"何かが、おかしい……","ENG":"Something's off...","TWN":"不太對勁……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"내가 느려졌나......?","JPN":"俺が鈍ってきたのか……？","ENG":"Am I moving slower?","TWN":"是我變慢了嗎……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아니면 설마...... 상대가 계속 강해지고 있는 건가?!","JPN":"それとも、まさか……相手が進化し続けている！？","ENG":"Or maybe... is she getting stronger?","TWN":"或者……該不會是對方一直在變強？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아!","JPN":"シルビア！","ENG":"Sylvia!","TWN":"希爾維亞！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"에너지 스캔 실시! 리플레이서 퀸의 리플레이서 인자 반응 확인해!","JPN":"エネルギースキャンを実施！　リプレイサー・クイーンのリプレイサーファクター反応を確認したまえ！","ENG":"Run the energy scanner! Check the Replacer Factor response of the Replacer Queen!","TWN":"執行能量掃描！確認克隆．女皇的克隆因子反應！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마? 갑자기 그건 왜......?","JPN":"おばさん？　いきなりどうして……？","ENG":"Maria? But why so suddenly?","TWN":"大嬸？怎麼突然要……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"빨리!","JPN":"早く！","ENG":"Now!","TWN":"快！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 알았어!","JPN":"わ、わかった！","ENG":"O-okay!","TWN":"是，知道了！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......이, 이건?","JPN":"……こ、これは？","ENG":"W-what's this?","TWN":"……這，這是？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마! 리플레이서 퀸의 육체를 구성하는 리플레이서 인자의 밀도가......","JPN":"おばさん！　リプレイサー・クイーンの体を構成するリプレイサーファクターの密度が……","ENG":"Maria! The density of Replacer Factors comprising Replacer Queen's body...","TWN":"大嬸！構成克隆．女皇肉體的克隆因子密度……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"처음보다 600% 이상 증가했어!","JPN":"最初に比べて600％以上、上がってる！","ENG":"It has increased by more than 600%!","TWN":"比一開始增加了600%以上！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"간이 스캔이라 정확도가 낮다고 해도 이건...... 말도 안 되는 증가치야!","JPN":"簡易スキャンで精度が低いとはいえ、これは……とんでもない数値よ！","ENG":"This is a portable scanner, so there can be a margin of error... But this number is plain unbelievable!","TWN":"就算簡易掃描的精度很低……但這增加得也太誇張了！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"설마...... 제물이라는 게......","JPN":"まさか……生贄というのは……","ENG":"No... Is this...","TWN":"難道……所謂的祭品……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이런 뜻이었나?","JPN":"こういう意味だったのか？","ENG":"Is this what you meant by \\"sacrifices?\\"","TWN":"就是這個意思嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"눈치챘나 보군. 이젠 너무 늦었지만.","JPN":"気づいたようだな。だが、もう手遅れだ。","ENG":"So you've caught on. But I'm afraid it's too late.","TWN":"妳發現了呢。但是已經太晚了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RSYSTEM_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>리플레이서 인자 진화 임계치 돌파.</color>","JPN":"<color=#ffd34c>リプレイサーファクターの進化臨界点を突破。</color>","ENG":"<color=#ffd34c>Replacer Factor evolution critical point reached.</color>","TWN":"<color=#ffd34c>突破克隆因子進化臨界值。</color>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L29_1","type":"dialog","speaker":"RSYSTEM_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>테라사이드 시스템의 직접관리 모드로 전환합니다.</color>","JPN":"<color=#ffd34c>テラサイドシステムの直接管理モードに切り替えます。</color>","ENG":"<color=#ffd34c>Changing to direct control mode of System Terraside.</color>","TWN":"<color=#ffd34c>切換為特拉賽德系統的直接管理模式。</color>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>관리주체 이전 완료.</color>","JPN":"<color=#ffd34c>管理元の移行完了。</color>","ENG":"<color=#ffd34c>System authority transfer complete.</color>","TWN":"<color=#ffd34c>管理實體移交完畢。</color>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L31_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>임계 리플레이서 인자 허수 에너지로 전환.</color>","JPN":"<color=#ffd34c>臨界リプレイサーファクターの虚数エネルギーに切替。</color>","ENG":"<color=#ffd34c>There was a significant physical loss due to the intervention of Imaginary Energy.</color>","TWN":"<color=#ffd34c>轉換為臨界克隆因子虛數能量。</color>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"크으윽!!","JPN":"くううっ！！","ENG":"Ugh!","TWN":"呃啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님! 괜찮으십니까?!","JPN":"大佐！　大丈夫ですか！？","ENG":"Colonel! Are you okay?","TWN":"上將！您還好嗎？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......함정이었군.","JPN":"……罠だったのだな。","ENG":"It was a trap.","TWN":"……原來是陷阱。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"설마 우리와의 전투를 통해 에너지를 흡수하고 있는 거였나?","JPN":"まさか、我々と戦いながらエネルギーを吸収していたのか？","ENG":"You've been absorbing energy during the fight.","TWN":"妳該不會是通過和我們的戰鬥，在吸收能量吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そのとおり。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"말했었지? 리플레이서 재생체는 재생할 때마다 더욱 진화한다고.","JPN":"言ったはずだ。リプレイサー再生体は、再生の度にさらなる進化を遂げると。","ENG":"Like I said... Regenerated Replacers evolve through repeated regenerations.","TWN":"我說過了吧？克隆再生體每次再生之後，就會更加進化。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"하지만 그 진화의 속도는 이전의 전투경험에 비례하기에 한계가 있지.","JPN":"だが、その進化のスピードは以前の戦闘経験に比例するものだから、限界がある。","ENG":"But there's a limit to the speed of evolution, because it's proportional to the amount of combat experience accumulated.","TWN":"然而進化速度會和之前的戰鬥經驗成正比，因此是有極限的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"하지만 지금 여기엔 최상급의 전투 경험을 충분히 쌓게 해 줄 제물들이 아주 많이 모여 있거든.","JPN":"今ここには、最上級の戦闘経験を十分に与えてくれる生贄が揃っている。","ENG":"But there are more than enough sacrifices available who would provide high quality resources.","TWN":"可是現在，這裡聚集了很多可以讓他們積累最上級戰鬥經驗的祭品。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"대량으로 증식한 리플레이서 나이트와 폰이 빠른 파괴, 재생 사이클을 거치면서 쌓인 진화 데이터는......","JPN":"大量に増殖したリプレイサー・ナイトとポーンが、\\n破壊と再生のサイクルを経て積み重ねた進化データは……","ENG":"The data of evolution accumulates through the rapid destruction and regeneration of Replacer Knight and Pawn and their splitters.","TWN":"大量增加的克隆．騎士和兵卒經由快速地破壞和再生的循環，所積累的進化資料……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"테라사이드 시스템을 통해 통합되어 최종적으로 내게 피드백 된다.","JPN":"テラサイドシステムを介して統合され、最終的には私のもとに来る。","ENG":"Then System Terraside compiles them all and delivers the final outcome to me,","TWN":"會透過特拉賽德系統進行統合，最終反饋到我這裡。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"리플레이서 인자가 프로그레시브 단계를 거쳐 그 최종형태에 도달할 때까지!","JPN":"リプレイサーファクターがプログレッシブ段階を経て、その最終形態に達するその時まで！","ENG":"until the Replacer Factors evolve past the Progressive stage and regain their complete primary form!","TWN":"直到克隆因子經過可操控階段，到達最終形態！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"최종 형태라고? 그게 대체......?","JPN":"最終形態だと？　それはいったい……？","ENG":"The primary form? What are you talking about?","TWN":"最終形態？那個究竟是……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"안토노프 사령관, 당신은 기억하고 있겠지?","JPN":"アントノフ司令官、あなたは覚えているだろう？","ENG":"I bet you remember this, Commander Antonov.","TWN":"安東諾夫司令官，妳還記得吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"이 절망의 고리를.","JPN":"この絶望のループを。","ENG":"This ring of despair.","TWN":"這種絕望的感覺。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리포트 레플리카 인자 조합 개시.</color>","JPN":"<color=#ffd34c>クリフォト・レプリカ・ファクターの組み合わせ開始。</color>","ENG":"<color=#ffd34c>Qliphoth Replica Factor integration initiated.</color>","TWN":"<color=#ffd34c>開始組合逆卡巴拉複製因子。</color>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L1_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>부분적 신성반응 활성화.</color>","JPN":"<color=#ffd34c>一部の神聖反応が活性化。</color>","ENG":"<color=#ffd34c>Partial divine pattern activated.</color>","TWN":"<color=#ffd34c>部分神聖反應活性化。</color>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>헤일로 – 기동.</color>","JPN":"<color=#ffd34c>ヘイロー起動。</color>","ENG":"<color=#ffd34c>Launching... Halo.</color>","TWN":"<color=#ffd34c>光環—啟動。</color>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"헤일로! 설마?!!","JPN":"ヘイロー！　まさか！？","ENG":"Halo? No, it can't be...","TWN":"光環！難道？！！"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"대정화 전쟁 최종전에서 나타났던 제 5종 침식체, 네임리스 원.","JPN":"大浄化戦争の最終戦で現れた第5種侵食体、ネームレスワン。","ENG":"The Nameless One, the Category 5 C.O. that made its appearance during the last phase of the Grand Purification War.","TWN":"淨化之戰最終戰役中出現的第5級侵蝕體，無名1。"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그 쇠락한 육신에서 채취한 변이 이터니움 결정이...... 바로 리플레이서 인자의 원형이다.","JPN":"その衰えた肉体から採取した変異エタニウム結晶が……まさにリプレイサーファクターの原型。","ENG":"We collected the mutated Eternium crystal from its withered body, which became the original form the Replacer Factor.","TWN":"從它衰敗的肉體中提取出來的永恆之金結晶……正是克隆因子的原型。"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"네임리스 원? 그게 뭐죠?","JPN":"ネームレスワン？　何です、それは？","ENG":"Nameless One? What’s that?","TWN":"無名1？那是什麼？"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대정화 전쟁 최종전이라면 아마도 북극점 공방전이었을 텐데......","JPN":"大浄化戦争の最終戦なら、おそらく北極点攻防戦のはずですが……","ENG":"The last phase of the Grand Purification War? She must be talking about the North Pole Battle.","TWN":"淨化之戰最終戰役，應該是指北極點的攻防戰吧……"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그곳에 네임리스 원이라는 침식체가 나타났다는 기록 같은 건 없습니다!","JPN":"そこにネームレスワンという侵食体が現れたという記録なんてありません！","ENG":"But I'm certain that there were no records about a Corrupted Object called the Nameless One!","TWN":"但那裡沒有出現名為無名1的侵蝕體紀錄啊！"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"네가 모른다고 해서 존재하지 않는다는 뜻은 아니지, 꼬마야.","JPN":"お前が知らないからって、存在していないことにはならないのよ、坊や。","ENG":"Just because you don't know about it doesn't mean that it doesn't exist, kiddo.","TWN":"你不知道不代表不存在啊，小子。"},"stage":{"bg":"MAINSTREAM_5503010","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"말도 안 되는 소리! 설사 당신 말이 맞는다고 해도 5종 침식체라니!","JPN":"そんなバカな！　もしあなたの言うとおりだとしても、第5種侵食体だなんて！","ENG":"That's nonsense! Even if you're telling the truth... A Category 5 C.O.?","TWN":"太荒唐了！就算妳說得沒錯，但5級侵蝕體這種事！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그런 분류는 이론상으로만 존재할 뿐인......","JPN":"そんなの理論上でしか存在しない……","ENG":"Such a thing only exists in theory!","TWN":"那種分類只有理論上才存在……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......아니, 리플레이서 퀸의 말은 사실이다. 카일.","JPN":"……いや、リプレイサー・クイーンの話は事実だ、カイル。","ENG":"What the Replacer Queen's saying is true, Kyle.","TWN":"……不，克隆·女皇說的是事實，凱爾。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"네, 네?!","JPN":"は、はい！？","ENG":"I-I'm sorry?","TWN":"什、什麼？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실제로 목격한 자들은 나와 도미닉, 그리고 극히 제한된 일부 인원뿐이지만......","JPN":"実際に目撃したのは私やドミニーク、そしてごく一部のメンバーだけだが……","ENG":"Although there were only a handful of people who witnessed it, including me and Dominic,","TWN":"實際上的目擊者只有我、多明尼克，和極少數的人……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"북극점 공방전 막바지에 분명 네임리스 원으로 명명된 미분류 침식체가 등장했었지.","JPN":"北極点攻防戦の終盤に、ネームレスワンと命名された未分類侵食体が出現したんだ。","ENG":"it's true that an unidentified C.O., later to be called the Nameless One, appeared at the end of the North Pole Battle.","TWN":"北極點攻防戰最後，確實出現了一個未分類，並且被命名為無名1的侵蝕體。"},"stage":{"bg":"MAINSTREAM_5503020","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"침식파 출력에 따른 추정 등급은 제 5종.","JPN":"侵食波出力からの推定ランクは、第5種。","ENG":"And based on the strength of Corruption rays emitted from it, its was rated a Category 5,","TWN":"根據侵蝕波功率推測是第5級。"},"stage":{"bg":"MAINSTREAM_5503020","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"단일 개체로 국가단위의 파멸을 초래할 수 있는 존재다.","JPN":"単独で国家級の破滅をもたらせるほどの存在だ。","ENG":"which means it was powerful enough to destroy a country single-handedly.","TWN":"那是個單一個體就可以毀滅國家單位的存在。"},"stage":{"bg":"MAINSTREAM_5503020","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하, 하지만 데이터베이스에는 그런 기록은 전혀......","JPN":"し、しかし、データベースにそんな記録は一切……","ENG":"B-but there was no such data in our database...","TWN":"但、但是資料庫裡完全沒有這種記錄……"},"stage":{"bg":"MAINSTREAM_5503020","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이미 전쟁은 마무리만 남은 시점이었어.","JPN":"すでに終戦に近いタイミングだった。","ENG":"The war was finally coming to an end at that point.","TWN":"那已經是戰爭的最後階段了。"},"stage":{"bg":"MAINSTREAM_5503020","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 상황에 제 5종 침식체라는 미증유의 존재가 나타났다는 기록을 공개할 수 있을 리가 없지.","JPN":"そんな状況で第5種侵食体という未曾有の存在が現れたという記録を公開できるはずもない。","ENG":"We couldn't let the public know that mankind faced another challenge; the unprecedented disaster of a Category 5 C.O.","TWN":"在那個情況下，要公開第5級侵蝕體這種前所未有的存在紀錄，是不可能的。"},"stage":{"bg":"MAINSTREAM_5503020","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"해당 정보는 관리국 최고관리위원회만 열람 가능한 기밀자료로 봉인처리 되었다.","JPN":"その情報は、管理局の最高管理委員会のみ閲覧できる機密情報として封印された。","ENG":"Any information regarding to it was sealed immediately, and only the High Committee of the Administration was allowed access to it.","TWN":"這個情報作為只有管理局最高管理委員會才能查閱的機密資料，被封印處理了，"},"stage":{"bg":"MAINSTREAM_5503020","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카일, 너도 비밀 정보 열람권이 있겠지만 네 등급으로는 근처에도 접근 불가능한 자료니까 처음 듣는 게 당연할 거다.","JPN":"カイル、君にも秘密情報の閲覧権があるだろうが、君のランクじゃ近寄れない情報だ。\\n初耳で当然だろう。","ENG":"I know you have access to confidential data, Kyle, but this is something that requires the highest-level security clearance. It's no wonder you haven't heard of it.","TWN":"凱爾，儘管你也有機密情報閱覽權，但以你的等級，是不可能取得那份資料的，所以你會第一次聽說也是當然的。"},"stage":{"bg":"MAINSTREAM_5503020","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5503020","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 그렇다 해도 이해가 되지 않는군.","JPN":"だが、それにしても納得いかないな。","ENG":"But still, it doesn't make any sense.","TWN":"但即使這樣，我還是無法理解。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"네임리스 원은 결국 격파하지 못했어.","JPN":"ネームレスワンは結局撃破できなかった。","ENG":"The Nameless One was too powerful for us to defeat.","TWN":"無名1到最後都沒有被打敗。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그러니 네임리스 원에게서 이터니움 결정을 채취할 수 있었을 리가 없다.","JPN":"だから、ネームレスワンからエタニウム結晶を採集するなんてあり得ないはず。","ENG":"There's no way you were able to collect the Eternium crystal from it.","TWN":"所以是不可能從無名1身上提取永恆之金結晶的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 녀석은 분명......","JPN":"あいつは、確か……","ENG":"I clearly remember that this C.O...","TWN":"那個傢伙明明……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그래, 나와 함께 초고심도 이면세계로 침몰했었지.","JPN":"そう、私とともに超高深度の裏世界に沈んだ。","ENG":"Yes, it sank to the hyperdepths of the Counterside with me.","TWN":"沒錯，和我一起沉沒到超深度的異界了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"뭐라고요? 저 이야기가 사실입니까, 중장님?","JPN":"何ですって？　事実ですか、中将？","ENG":"What? Is that true, Lieutenant General?","TWN":"什麼？這件事是真的嗎，中將大人？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그럼 리플레이서 퀸의 희생으로...... 제 5종 침식체를 막아냈다는 건가요?","JPN":"リプレイサー・クイーンの犠牲によって……第5種侵食体を封じ込めたと？","ENG":"Was it because of her sacrifice that we were able to fend off a Category 5 C.O.?","TWN":"那麼是用克隆．女皇的犧牲……阻止了5級侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうだ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"네임리스 원은 일종의...... 불멸체 같은 거였다.","JPN":"ネームレスワンはある種の……不滅体みたいなものだった。","ENG":"The Nameless One was, to put it simply, an immortal being.","TWN":"無名1侵蝕體就像是一種……不滅者。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제압한다고 해도 완전히 소멸시킬 수가 없었어.","JPN":"制圧しても、完全に消滅させることは無理だった。","ENG":"We just couldn't put it out of existence.","TWN":"就算能壓制它，也無法使它完全消滅。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래서 나와 도미닉이 시간을 버는 사이에 제이나가 놈을 차원함선으로도 접근할 수 없는 이면세계 깊은 곳으로 끌고가 버린 거다.","JPN":"だから、私とドミニークが時間稼ぎをする間に、ジェイナが奴を引きずり込んだんだ。\\n次元艦船でも近づけない、裏世界の奥地へ。","ENG":"So while Dominic and I stalled for time, Jaina dragged it to the deepest part of the Counterside, where no dimension ships could ever reach.","TWN":"所以我和多明尼克在拖延時間的時候，婕娜就把那個傢伙帶到了連次元艦船都無法到達的異界深處。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당시 놈을 현실세계에서 추방할 방법은 그것뿐이었으니까.","JPN":"当時、奴を現実世界から追放する方法はそれしかなかったんだ。","ENG":"That was the only way we could drive it away from the Normalside.","TWN":"當時要把那傢伙驅逐出現實世界，就只有這個方法了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그럴 수가......","JPN":"そんな……","ENG":"No way...","TWN":"怎麼可能……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그럼 저 여자가 인류의 영웅이라는 거잖습니까?!","JPN":"つまり、あの女が人類の英雄ということじゃないですか！？","ENG":"That means that woman saved our planet!","TWN":"這麼說那個女人才是人類的英雄了？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그런 셈이지...... 아는 사람은 거의 없는 사실이지만.","JPN":"そんなところだ……この事実を知る人間はほとんどいないが。","ENG":"You're right. Although there aren't many who know about it.","TWN":"算是吧……雖然幾乎沒有人知道這件事。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"네가 네임리스 원을 처치한 건가? 침몰한 곳에서?","JPN":"君がネームレスワンを倒したのか？　引きずり込んだところで？","ENG":"Were you able to defeat the Nameless One after you sank?","TWN":"所以妳打倒了無名1？在沉沒的地方？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"날 너무 과대평가하는군.","JPN":"私のことを買いかぶりすぎではないでしょうか？","ENG":"That would be overestimating me.","TWN":"妳也太高估我了吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"당신과 부사령관님도 어쩌지 못한 괴물을 나 혼자 처치할 수 있을 리가 없잖아?","JPN":"あなたや副司令官様でさえ始末できなかった怪物を、私一人で退治できるわけがないだろう？","ENG":"That was a tough enemy even for you and Deputy Commander together. There was no way I could kill it.","TWN":"妳和副司令官都對付不了的怪物，我一個人又能拿它怎麼樣？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"하지만 네임리스 원은 그 시점에서 사실상 수명이 거의 끝난 상태였어.","JPN":"でもネームレスワンは、その時点ですでに寿命がほとんど尽きていた。","ENG":"But at that point, the Nameless One was already near death.","TWN":"但是無名1在那個時點，壽命已經是幾乎要終結的狀態。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"난 스스로 붕괴한 놈의 사체에서 채취한 이터니움으로 간신히 살아 남을 수 있었지.","JPN":"私は自ら滅びた奴の死体からエタニウムを採集して、やっとのことで生き延びることができた。","ENG":"I barely managed to carry on using the Eternium I collected from its body after it collapsed on its own...","TWN":"我是從自身崩壞的怪物屍體中提取出了永恆之金，好不容易才活下來。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"부사령관님이 구출해 주기 전까지.","JPN":"副司令官様が私を救い出してくれるまで。","ENG":"until Deputy Commander came to rescue me.","TWN":"直到副司令官救出我。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도미닉이......?","JPN":"ドミニークが……？","ENG":"Dominic rescued you?","TWN":"多明尼克……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그리고 나와 부사령관님은 그때 얻은 이터니움 결정의 구조를 토대로 네임리스 원의 육신을 분석하기 시작했고......","JPN":"そして、私と副司令官様はその時に手に入れたエタニウム結晶をもとに、\\nネームレスワンの肉体を分析し始め……","ENG":"Then Deputy Commander and I started studying the Nameless One based on the structure of the Eternium crystal I obtained.","TWN":"然後我和副司令官以獲得的永恆之金結晶構造為基礎，開始分析無名1的肉體……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"마침내 이 자리에서 다시 한 번 그 육신을 재구성하는 데 성공했다.","JPN":"ついに、この場であの肉体を再現するのに成功した。","ENG":"And here and now, we finally succeeded in reproducing its body.","TWN":"最後，就在這裡，我再度成功地重組了那個怪物的肉體。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"멋모르고 우리의 진화를 가속시켜 준 너희의 도움을 받아서 말이지.","JPN":"何も知らずに、我々の進化を加速させてくれたお前らのおかげでな。","ENG":"And it was all thanks to you. You kindly sped up the evolution process without even knowing it.","TWN":"這都多虧了你們毫不知情地加速了我們的進化。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님!","JPN":"中将！","ENG":"Lieutenant General!","TWN":"中將大人！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이건...... 정말 위험해 보이는데?","JPN":"これは……本気でヤバそうだけど？","ENG":"This looks... seriously dangerous.","TWN":"這個……好像真的很危險啊？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"마리아 안토노프. 당신을 싫어한 건 아니었지만......","JPN":"マリア・アントノフ、あなたのことを嫌っていたわけではないが……","ENG":"Maria Antonov. I've never hated you.","TWN":"瑪麗亞．安東諾夫，我並不討厭妳……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"우리의 오랜 인연도 정리할 때가 온 것 같군.","JPN":"我々の因縁を終わりにする時がきたようだ。","ENG":"But I guess this is the end of our long relationship.","TWN":"但好像到了該清算我們長年孽緣的時候了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"부사령관님의 이상을 위해, 이 곳에서 사라져라.","JPN":"副司令官様の理想のために、ここで消えろ。","ENG":"For the Deputy Commander's ideals, I'll make you disappear from this place...","TWN":"為了副司令官的理想，妳就在這裡消失吧！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"영원히!","JPN":"永遠に！","ENG":"forever!","TWN":"永遠地！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};